  1391	/* This is like dictGetRandomKey() from the POV of the API, but will do more
  1392	 * work to ensure a better distribution of the returned element.
  1393	 *
  1394	 * This function improves the distribution because the dictGetRandomKey()
  1395	 * problem is that it selects a random bucket, then it selects a random
  1396	 * element from the chain in the bucket. However elements being in different
  1397	 * chain lengths will have different probabilities of being reported. With
  1398	 * this function instead what we do is to consider a "linear" range of the table
  1399	 * that may be constituted of N buckets with chains of different lengths
  1400	 * appearing one after the other. Then we report a random element in the range.
  1401	 * In this way we smooth away the problem of different chain lengths. */
  1402	#define GETFAIR_NUM_ENTRIES 15
  1403	dictEntry *dictGetFairRandomKey(dict *d) {
  1404	    dictEntry *entries[GETFAIR_NUM_ENTRIES];
  1405	    unsigned int count = dictGetSomeKeys(d,entries,GETFAIR_NUM_ENTRIES);
  1406	    /* Note that dictGetSomeKeys() may return zero elements in an unlucky
  1407	     * run() even if there are actually elements inside the hash table. So
  1408	     * when we get zero, we call the true dictGetRandomKey() that will always
  1409	     * yield the element if the hash table has at least one. */
  1410	    if (count == 0) return dictGetRandomKey(d);
  1411	    unsigned int idx = rand() % count;
  1412	    return entries[idx];
