   438	/* Save a string object as [len][data] on disk. If the object is a string
   439	 * representation of an integer value we try to save it in a special form */
   440	ssize_t rdbSaveRawString(rio *rdb, unsigned char *s, size_t len) {
   441	    int enclen;
   442	    ssize_t n, nwritten = 0;
   443	
   444	    /* Try integer encoding */
   445	    if (len <= 11) {
   446	        unsigned char buf[5];
   447	        if ((enclen = rdbTryIntegerEncoding((char*)s,len,buf)) > 0) {
   448	            if (rdbWriteRaw(rdb,buf,enclen) == -1) return -1;
   449	            return enclen;
   450	        }
   451	    }
   452	
   453	    /* Try LZF compression - under 20 bytes it's unable to compress even
   454	     * aaaaaaaaaaaaaaaaaa so skip it */
   455	    if (server.rdb_compression && len > 20) {
   456	        n = rdbSaveLzfStringObject(rdb,s,len);
   457	        if (n == -1) return -1;
   458	        if (n > 0) return n;
   459	        /* Return value of 0 means data can't be compressed, save the old way */
   460	    }
   461	
   462	    /* Store verbatim */
   463	    if ((n = rdbSaveLen(rdb,len)) == -1) return -1;
   464	    nwritten += n;
   465	    if (len > 0) {
   466	        if (rdbWriteRaw(rdb,s,len) == -1) return -1;
   467	        nwritten += len;
   468	    }
   469	    return nwritten;
   470	}
