   503	/* Load a string object from an RDB file according to flags:
   504	 *
   505	 * RDB_LOAD_NONE (no flags): load an RDB object, unencoded.
   506	 * RDB_LOAD_ENC: If the returned type is a Redis object, try to
   507	 *               encode it in a special way to be more memory
   508	 *               efficient. When this flag is passed the function
   509	 *               no longer guarantees that obj->ptr is an SDS string.
   510	 * RDB_LOAD_PLAIN: Return a plain string allocated with zmalloc()
   511	 *                 instead of a Redis object with an sds in it.
   512	 * RDB_LOAD_SDS: Return an SDS string instead of a Redis object.
   513	 * RDB_LOAD_HFLD: Return a hash field object (mstr)
   514	 * RDB_LOAD_HFLD_TTL: Return a hash field with TTL metadata reserved
   515	 *
   516	 * On I/O error NULL is returned.
   517	 */
   518	void *rdbGenericLoadStringObject(rio *rdb, int flags, size_t *lenptr) {
   519	    void *buf;
   520	    int plainFlag = flags & RDB_LOAD_PLAIN;
   521	    int sdsFlag = flags & RDB_LOAD_SDS;
   522	    int hfldFlag = flags & (RDB_LOAD_HFLD|RDB_LOAD_HFLD_TTL);
   523	    int robjFlag = (!(plainFlag || sdsFlag || hfldFlag)); /* not plain/sds/hfld */
   524	
   525	    int isencoded;
   526	    unsigned long long len;
   527	
   528	    len = rdbLoadLen(rdb,&isencoded);
   529	    if (len == RDB_LENERR) return NULL;
   530	
   531	    if (isencoded) {
   532	        switch(len) {
   533	        case RDB_ENC_INT8:
   534	        case RDB_ENC_INT16:
   535	        case RDB_ENC_INT32:
   536	            return rdbLoadIntegerObject(rdb,len,flags,lenptr);
   537	        case RDB_ENC_LZF:
   538	            return rdbLoadLzfStringObject(rdb,flags,lenptr);
   539	        default:
   540	            rdbReportCorruptRDB("Unknown RDB string encoding type %llu",len);
   541	            return NULL;
   542	        }
   543	    }
   544	
   545	    /* return robj */
   546	    if (robjFlag) {
   547	        robj *o = tryCreateStringObject(SDS_NOINIT,len);
   548	        if (!o) {
   549	            serverLog(isRestoreContext()? LL_VERBOSE: LL_WARNING, "rdbGenericLoadStringObject failed allocating %llu bytes", len);
   550	            return NULL;
   551	        }
   552	        if (len && rioRead(rdb,o->ptr,len) == 0) {
   553	            decrRefCount(o);
   554	            return NULL;
   555	        }
   556	        return o;
   557	    }
   558	
   559	    /* plain/sds/hfld */
   560	    if (plainFlag) {
   561	        buf = ztrymalloc(len);
   562	    } else if (sdsFlag) {
   563	        buf = sdstrynewlen(SDS_NOINIT,len);
   564	    }  else { /* hfldFlag */
   565	        buf = hfieldTryNew(NULL, len, (flags&RDB_LOAD_HFLD) ? 0 : 1);
