void defragWhileBlocked(void) {
    /* This is called infrequently, while timers are not active. We might need to start defrag. */
    if (!defragIsRunning()) activeDefragCycle();

    if (!defragIsRunning()) return;

action.new_str:
void defragWhileBlocked(void) {
    /* Loading may call processEventsWhileBlocked() from inside DB flush/load
     * paths. Avoid moving dictionaries or objects that the caller may currently
     * be iterating or freeing synchronously. */
    if (server.loading) return;

    /* This is called infrequently, while timers are not active. We might need to start defrag. */
    if (!defragIsRunning()) activeDefragCycle();

    if (!defragIsRunning()) return;

